Here's a simple C++ function that converts a Markdown-formatted string to HTML:

```cpp
#include <string>
#include <sstream>
#include <iostream>
#include <stdexcept>

std::string markdown_to_html(const std::string& markdown) {
    std::stringstream ss;
    ss << "<html>\n<body>\n";

    for (const auto& c : markdown) {
        switch (c) {
            case '#':
                ss << "<h1>";
                while (markdown[ss.tellp()] == '#') {
                    ss << "#";
                    ss.seekp(1, std::ios_base::cur);
                }
                ss << "</h1>";
                break;
            case '*':
            case '_':
                ss << "<em>";
                while (c == markdown[ss.tellp()]) {
                    ss.seekp(1, std::ios_base::cur);
                    c = markdown[ss.tellp()];
                }
                ss << "</em>";
                break;
            case '[':
                bool is_link = false;
                std::string link_text;
                std::string link_url;
                while (markdown[ss.tellp()] != ']') {
                    if (markdown[ss.tellp()] == '(') {
                        is_link = true;
                        while (markdown[ss.tellp()] != ')') {
                            ss.seekp(1, std::ios_base::cur);
                        }
                    } else {
                        link_text += markdown[ss.tellp()];
                        ss.seekp(1, std::ios_base::cur);
                    }
                }
                if (is_link) {
                    ss << "<a href=\"";
                    while (markdown[ss.tellp()] != '(') {
                        ss.seekp(1, std::ios_base::cur);
                    }
                    while (markdown[ss.tellp()] != ')') {
                        link_url += markdown[ss.tellp()];
                        ss.seekp(1, std::ios_base::cur);
                    }
                    ss << "\">" << link_text << "</a>";
                } else {
                    ss << link_text;
                }
                break;
            case '>':
                ss << "<blockquote>";
                while (markdown[ss.tellp()] != '\n') {
                    ss.seekp(1, std::ios_base::cur);
                }
                ss << "</blockquote>";
                break;
            default:
                ss << c;
        }
    }

    ss << "</body>\n</html>";
    return ss.str();
}
```

This function uses a `std::stringstream` to build the HTML output. It supports the following Markdown elements:

* Headings (`#` character)
* Emphasis (`*` or `_` character)
* Links (`[` and `]` characters)
* Block quotes (`>` character)

